scwin.arrSelpchItemCd = ["0001", "0068", "0069", "0070", "0071", "0047", "0048", "0049", "0050", "0066", "0056"];
scwin.onpageload = function () {
  //2026-04-24 Excel등록 숨김 정영수P 요청.
  rd_upload.hide();
  btn_excel.hide();
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  scwin.f_defaultValue();
  $c.gus.cfDisableObjects($p, [btn_save]);

  //컬럼 못 움직이기때문에 컬럼저장 버튼이 필요없음.
  udc_gr_basetrf_topGridBtn.setHideBtn('btn_userSave', "true");
  udc_gr_basetrfList_topGridBtn.setHideBtn('btn_userSave', "true");
  rd_upload.setValue("0");
};

//-------------------------------------------------------------------------
// function name : f_defaultValue
// function desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
  $c.gus.cfDisableKey($p);
};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  ds_basetrfList.removeAll();
  if (!(await scwin.f_validChk())) {
    return;
  }
  sbm_retrieveBasetrf.action = "/ds.lo.comntrfmgnt.RetrieveBasisAnnouncementTariffListCMD.do" + "?adptDt=" + ed_cnd_adptDt.getValue().trim() + "&portDistrictCd=" + txt_cnd_portDistrictCd.getValue().trim();

  //submit 처리.
  let objSubmit = await $c.sbm.execute($p, sbm_retrieveBasetrf);
  // if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
  //     await scwin.sbm_retrieveBasetrf_submitdone();
  // }
};
scwin.sbm_retrieveBasetrf_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  //for=ds_basetrf event=OnLoadCompleted
  scwin.showTotalRows(txt_total, ds_basetrf.getRowCount());

  //조회 이후 젤 처음 row 로 focus 이동처리.
  if (ds_basetrf.getRowCount() > 0) {
    gr_basetrf.setFocusedCell(0, "portDistrictNm");
  }
};

//-------------------------------------------------------------------------
// function name : f_validChk
// function desc : 필수 조회 조건 check
//-------------------------------------------------------------------------
scwin.f_validChk = async function () {
  if (ds_basetrf.getModifiedIndex().length > 0) {
    let check = await $c.win.confirm($p, scwin.MSG_LO_CRM_001);
    if (!check) {
      return false;
    }
  }
  let adptDt = ed_cnd_adptDt.getValue();
  if (adptDt != "" && adptDt.length != 8) {
    $c.win.alert($p, scwin.MSG_LO_ERR_001);
    return false;
  }
  return true;
};

//-------------------------------------------------------------------------
// function name : f_New
// function desc : 신규
//-------------------------------------------------------------------------
scwin.f_New = async function () {
  ed_adptDt.setValue(scwin.strCurDate);
  txt_portDistrictCd.setValue("");
  txt_portDistrictNm.setValue("");
  var nRow = ds_basetrf.getRowCount();
  ds_basetrf.insertRow(nRow);
  ds_basetrf.setCellData(nRow, "portDistrictCd", txt_portDistrictCd.getValue().trim());
  ds_basetrf.setCellData(nRow, "portDistrictNm", txt_portDistrictNm.getValue().trim());
  ds_basetrf.setCellData(nRow, "adptDt", ed_adptDt.getValue().trim());
  gr_basetrf.setFocusedCell(nRow, "portDistrictNm");
  sbm_newBasetrfList.action = "/ds.lo.comntrfmgnt.CreateNewRegistItemCMD.do" + "?adptDt=" + ds_basetrf.getCellData(nRow, "adptDt");

  //submit 처리.
  let objSubmit = await $c.sbm.execute($p, sbm_newBasetrfList);
  if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_newBasetrfList_submitdone();
  }
};
scwin.sbm_newBasetrfList_submitdone = async function (e) {
  ds_basetrfList.removeAll();
  let jsonData = ds_NewbasetrfList.getAllJSON();
  ds_basetrfList.setJSON(jsonData);
  ds_basetrfList.modifyAllStatus('C');
  scwin.f_CreateDs();
  gr_basetrfList.setReadOnly("column", "unitCd", false);
  gr_basetrfList.setReadOnly("column", "comnTrf1", false);
  gr_basetrfList.setReadOnly("column", "comnTrf2", false);
  gr_basetrfList.setReadOnly("column", "comnTrf6", false);
  gr_basetrfList.setReadOnly("column", "comnTrf10", false);
  gr_basetrfList.setReadOnly("column", "comnTrf11", false);
  $c.gus.cfEnableObjects($p, [btn_save, ed_adptDt, txt_portDistrictCd, txt_portDistrictNm, imgPortPop]);
  $c.gus.cfDisableObjects($p, [btn_Edit, btn_new]);
  scwin.showTotalRows(txt_total, ds_basetrf.getRowCount());
};

//-------------------------------------------------------------------------
// function name : f_Edit
// function desc : 수정
//-------------------------------------------------------------------------
scwin.f_Edit = function () {
  gr_basetrfList.setReadOnly("column", "unitCd", false);
  gr_basetrfList.setReadOnly("column", "comnTrf1", false);
  gr_basetrfList.setReadOnly("column", "comnTrf2", false);
  gr_basetrfList.setReadOnly("column", "comnTrf6", false);
  gr_basetrfList.setReadOnly("column", "comnTrf10", false);
  gr_basetrfList.setReadOnly("column", "comnTrf11", false);
  $c.gus.cfEnableObjects($p, [btn_save]);
  $c.gus.cfDisableObjects($p, [btn_Edit, btn_new]);
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  let reqCheck = await scwin.f_ReqFieldChk();
  if (!reqCheck) {
    return;
  }
  let confirm = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (confirm) {
    //submit 처리.
    let objSubmit = await $c.sbm.execute($p, sbm_save);
    // if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
    //     await scwin.sbm_save_submitdone();
    // }
  }
};
scwin.sbm_save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  await $c.win.alert($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다 
  //ds_basetrf.modifyAllStatus("R");
  ds_basetrf.reform();
  scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// function name : f_ReqFieldChk
// function desc : 필수 입력항목 체크
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = async function () {
  let chkCnt = 0;
  for (i = 0; i < ds_RealbasetrfList.getRowCount(); i++) {
    if (ds_RealbasetrfList.getCellData(i, "selpchItemCd") == scwin.arrSelpchItemCd[0] && ds_RealbasetrfList.getCellData(i, "comnTrf") == "0") {
      chkCnt++;
    }
  }
  if (chkCnt > 0) {
    await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "선내")); // 필수입력 check
    return false;
  }
  return true;
};

//-------------------------------------------------------------------------
// function name : f_CreateDs
// function desc : 그리드DataId의 dataset을 서버로 넘길 dataset으로 변경
//-------------------------------------------------------------------------
scwin.f_CreateDs = function () {
  let i = 0;
  let j = 0;
  ds_RealbasetrfList.removeAll();
  let baseRowIndex = ds_basetrf.getRowPosition();
  for (i = 0; i < ds_basetrfList.getRowCount(); i++) {
    for (j = 1; j <= 11; j++) {
      var nRow = ds_RealbasetrfList.getRowCount();
      ds_RealbasetrfList.insertRow(nRow);
      ds_RealbasetrfList.setCellData(nRow, "adptDt", ds_basetrf.getCellData(baseRowIndex, "adptDt"));
      ds_RealbasetrfList.setCellData(nRow, "portDistrictCd", ds_basetrf.getCellData(baseRowIndex, "portDistrictCd"));
      ds_RealbasetrfList.setCellData(nRow, "selpchItemCd", scwin.arrSelpchItemCd[j - 1]);
      ds_RealbasetrfList.setCellData(nRow, "commCd", ds_basetrfList.getCellData(i, "commCd"));
      ds_RealbasetrfList.setCellData(nRow, "comnTrfSeq", ds_basetrfList.getCellData(i, "comnTrfSeq"));
      ds_RealbasetrfList.setCellData(nRow, "famtFratClsCd", ds_basetrfList.getCellData(i, "famtFratClsCd"));
      ds_RealbasetrfList.setCellData(nRow, "unitCd", ds_basetrfList.getCellData(i, "unitCd"));
      ds_RealbasetrfList.setCellData(nRow, "comnTrf", ds_basetrfList.getCellData(i, ds_basetrfList.getColumnID(j + 4)));
    }
  }
};

