scwin.f_chgField = async function (chgComp1, chgComp2, disGubun) {
  if (chgComp1.getValue().trim() == "") {
    chgComp2.setValue("");
  } else {
    await scwin.f_openPopUp(disGubun, "T");
  }

  //변경된 항구를 데이타셋에 반영
  let baseRowIndex = ds_basetrf.getRowPosition();
  if (ds_basetrf.getRowStatus(baseRowIndex) == "C") {
    ds_basetrf.setCellData(baseRowIndex, "portDistrictCd", txt_portDistrictCd.getValue().trim());
    ds_basetrf.setCellData(baseRowIndex, "portDistrictNm", txt_portDistrictNm.getValue().trim());
    for (let i = 0; i < ds_RealbasetrfList.getRowCount(); i++) {
      ds_RealbasetrfList.setCellData(i, "adptDt", ds_basetrf.getCellData(baseRowIndex, "adptDt"));
      ds_RealbasetrfList.setCellData(i, "portDistrictCd", ds_basetrf.getCellData(baseRowIndex, "portDistrictCd"));
    }
  }
};

//-------------------------------------------------------------------------
// 화면이동
//-------------------------------------------------------------------------
scwin.f_winOpen = async function () {
  let baseRowIndex = ds_basetrf.getRowPosition();
  if (ds_basetrf.getCellData(baseRowIndex, "portDistrictCd") != "") {
    $c.win.alert($p, scwin.MSG_LO_INF_001);
    return;
  }
  for (let i = 0; i < ds_basetrfList.getRowCount(); i++) {
    if (ds_basetrfList.getRowStatus(i) != "R") {
      $c.win.alert($p, scwin.MSG_LO_INF_002);
      return;
    }
  }
  let data = {
    "adptDt": ed_adptDt.getValue()
  };
  //TODO : 크기 등 값 확인
  let opts = {
    id: "popup",
    popupName: "매출계획구분등록 자동생성"
  };
  let vRtnValue = await $c.win.openPopup($p, "/ui/ds/lo/comntrfmgnt/lo_200_01_02p.xml", opts, data);
  if (vRtnValue == null) {
    return;
  }
  await scwin.f_Retrieve();
  for (let i = 0; i < ds_basetrf.getRowCount(); i++) {
    if (ds_basetrf.getCellData(i, "adptDt") == vRtnValue[0] && ds_basetrf.getCellData(i, "portDistrictCd") == vRtnValue[1]) {
      ds_basetrf.setRowPosition(i);
    }
  }
};

