//for=ds_basetrf event=CanRowPosChange
scwin.ds_basetrf_onbeforerowpositionchange = async function (info) {
  var sRtn = true;
  if (ds_basetrfList.getModifiedIndex().length > 0) {
    ds_basetrf.unbind("onrowpositionchange");
    var blChk = await $c.win.confirm($p, scwin.MSG_LO_CRM_001);
    if (blChk == false) {
      sRtn = blChk;
      ds_basetrf.setRowPosition(info.oldRowIndex, true);
      ds_basetrf.bind("onrowpositionchange", "scwin.ds_basetrf_onrowpositionchange");
    } else {
      //ds_basetrf.undoRow(info.oldRowIndex);
      ds_basetrf.removeRow(info.oldRowIndex);
      sRtn = blChk;
      ds_basetrf.bind("onrowpositionchange", "scwin.ds_basetrf_onrowpositionchange");
      var paramJSON = {
        oldRowIndex: info.oldRowIndex,
        newRowIndex: info.newRowIndex
      };
      ds_basetrf.trigger("onrowpositionchange", [paramJSON]);
    }
  }
  return sRtn;
};

//for=ds_basetrf event=OnRowPosChanged
