scwin.gr_basetrfList_onafteredit = async function (rowIndex, columnIndex, value) {
  if (scwin.gr_basetrfList_beforeCellChgInfos != undefined && scwin.gr_basetrfList_beforeCellChgInfos != null && scwin.gr_basetrfList_beforeCellChgInfos != "" && Object.keys(scwin.gr_basetrfList_beforeCellChgInfos).length > 0) {
    var cellRow = scwin.gr_basetrfList_beforeCellChgInfos.rowIndex;
    var cellID = scwin.gr_basetrfList_beforeCellChgInfos.colID;
    var cellOldVal = scwin.gr_basetrfList_beforeCellChgInfos.oldValue;
    if (rowIndex == cellRow && gr_basetrfList.getColumnID(columnIndex) == cellID) {
      // alert(9);            
      await scwin.gr_basetrfList_OnExit(cellRow, cellID, cellOldVal);
    } else {
      if (gr_basetrfList.getColumnID(columnIndex) == "unitCd" && value == "") {
        scwin.eventProEndFlag = true;
      }
    }
  }
};
